type IntList = list[int]

@abstract
class DataFormatter:
    @abstract
    def format(self, items: IntList) -> str: ...

class PrefixSuffixFormatter(DataFormatter):
    @override
    def format(self, items: IntList) -> str:
        if len(items) < 2:
            return f"len={len(items)}"
        first, *rest = items
        if len(rest) == 0:
            return f"single:{first}"
        *middle, last = rest
        total: int = first + last
